# 客運（Guest Movements）— 以大運為初運，按五行相生推五步
# 客運太少按大運定，陽年太→少→太→少→太，陰年少→太→少→太→少
def _get_keyun_order(dayun_wuxing: str, dayun_taishao: str):
    """計算客運五步順序"""
    wuxing_cycle = ["木", "火", "土", "金", "水"]
    taishao_cycle = ["太", "少"] if dayun_taishao.startswith("太") else ["少", "太"]
    start_idx = wuxing_cycle.index(dayun_wuxing)
    result = []
    names = ["初運", "二運", "三運", "四運", "終運"]
    yins = ["角", "徵", "宮", "商", "羽"]
    for i in range(5):
        wx_idx = (start_idx + i) % 5
        ts = taishao_cycle[i % 2]
        wuxing = wuxing_cycle[wx_idx]
        yin = yins[wx_idx]
        result.append((names[i], wuxing, yin, f"{ts}{yin}"))
    return result

