def get_keqi_steps(sitian: str) -> list:
    """
    計算客氣六步（以司天為三之氣）

    按《素問·六微旨大論》：
    三之氣=司天，六步依次排列。

    步序：厥陰(0)→少陰(1)→太陰(2)→少陽(3)→陽明(4)→太陽(5)

    參數：
        sitian (str): 司天之氣名稱（如"少陰君火"）

    回傳：
        list: 六步客氣名稱列表，索引0=初之氣,...,5=終之氣
    """
    sitian_step = LIUQI_STEP_ORDER.index(sitian)
    # 三之氣(index 2)=司天，所以初之氣在 (sitian_step - 2) % 6
    start = (sitian_step - 2) % 6
    return [LIUQI_STEP_ORDER[(start + i) % 6] for i in range(6)]

