# ============================================================
# 天干地支六十花甲（60-Year Cycle）
# ============================================================
def _build_jiazi_cycle():
    """建立六十甲子循環"""
    cycle = []
    for i in range(60):
        tg = TIANGAN[i % 10]
        dz = DIZHI[i % 12]
        cycle.append(f"{tg}{dz}")
    return cycle

JIAZI_CYCLE = _build_jiazi_cycle()

def get_ganzhi(year: int) -> tuple:
    """
    從西曆年份取得干支年

    參數：
        year (int): 西曆年份（如2024）

    回傳：
        (str, str, str): (天干, 地支, 干支組合) 如 ("甲", "子", "甲子")

    算法：
        甲子年 = 公元4年（甲子紀年基準）
        offset = (year - 4) % 60
    """
    offset = (year - 4) % 60
    gz = JIAZI_CYCLE[offset]
    tg = gz[0]
    dz = gz[1]
    return tg, dz, gz

